spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var boxY = H / 2 - 35;
    var b1x = W / 2 - 65;
    var b2x = W / 2;
    var b3x = W / 2 + 65;
    var radius = 4.5;

    // Stages:
    // 0 - 3s: Box 1 only
    // 3s - 6.5s: Box 2 appears
    // 6.5s - 9.5s: Box 3 appears
    // 9.5s - 12s: Highlight all

    var stage = 1;
    if (progress >= 0.25 && progress < 0.54) stage = 2;
    else if (progress >= 0.54 && progress < 0.79) stage = 3;
    else if (progress >= 0.79) stage = 4;

    // Helper to draw balls in a box
    function drawBoxGroup(bx, by, redCount, blueCount, drawOpacity) {
      var boxW = 40;
      var boxH = 50;
      ctx.strokeStyle = 'rgba(75, 85, 99, ' + drawOpacity + ')';
      ctx.lineWidth = 1.5;
      ctx.strokeRect(bx - boxW/2, by - boxH/2, boxW, boxH);

      // Draw balls inside box
      var cols = 2;
      var spacingX = 12;
      var spacingY = 10;

      // Red balls first
      for (var i = 0; i < redCount; i++) {
        var col = i % cols;
        var row = Math.floor(i / cols);
        var rx = bx - 10 + col * spacingX;
        var ry = by - 16 + row * spacingY;
        ctx.fillStyle = 'rgba(239, 68, 68, ' + drawOpacity + ')';
        ctx.beginPath();
        ctx.arc(rx, ry, radius, 0, Math.PI * 2);
        ctx.fill();
      }

      // Blue balls
      for (var j = 0; j < blueCount; j++) {
        var idx = redCount + j;
        var col = idx % cols;
        var row = Math.floor(idx / cols);
        var bx = bx - 10 + col * spacingX;
        var by = by - 16 + row * spacingY;
        ctx.fillStyle = 'rgba(59, 130, 246, ' + drawOpacity + ')';
        ctx.beginPath();
        ctx.arc(bx, by, radius, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    // Box 1 (Always visible)
    drawBoxGroup(b1x, boxY, 1, 3, 1.0);
    ctx.fillStyle = '#3B82F6';
    ctx.font = 'bold 11px monospace';
    ctx.textAlign = 'center';
    ctx.fillText('1:3', b1x, boxY + 38);

    // Box 2
    if (stage >= 2) {
      drawBoxGroup(b2x, boxY, 2, 6, 1.0);
      ctx.fillStyle = '#10B981';
      ctx.fillText('2:6', b2x, boxY + 38);
    } else {
      drawBoxGroup(b2x, boxY, 2, 6, 0.15);
    }

    // Box 3
    if (stage >= 3) {
      drawBoxGroup(b3x, boxY, 3, 9, 1.0);
      ctx.fillStyle = '#F59E0B';
      ctx.fillText('3:9', b3x, boxY + 38);
    } else {
      drawBoxGroup(b3x, boxY, 3, 9, 0.15);
    }

    // Explanations
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillStyle = '#9CA3AF';
    ctx.textAlign = 'center';

    if (stage === 1) {
      ctx.fillStyle = '#3B82F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Base Ratio (1 : 3)', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('1 red circle and 3 blue circles.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Double the Group (2 : 6)', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Multiply both terms by 2: (1×2) : (3×2) = 2 : 6.', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#F59E0B';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Triple the Group (3 : 9)', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Multiply both terms by 3: (1×3) : (3×3) = 3 : 9.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('1:3  =  2:6  =  3:9', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('All three boxes represent the exact same proportion of red to blue.', W / 2, H - 22);
    }
  }
};
